#[cfg(test)]
mod tests {
    use std::collections::HashMap;

    use petgraph::graph::NodeIndex;

    use super::super::dep_graph::{DepEdge, DepNode, DepNodeKind, DependencyGraph};
    use super::*;

    /// 构建一个简单的测试依赖图用于单元测试
    ///
    /// 节点关系：
    ///   A → B → C
    ///   (无循环)
    fn build_acyclic_graph() -> DependencyGraph {
        let mut graph = DependencyGraph::new();

        let a = DepNode { id: "a".into(), name: "a".into(), kind: DepNodeKind::File };
        let b = DepNode { id: "b".into(), name: "b".into(), kind: DepNodeKind::File };
        let c = DepNode { id: "c".into(), name: "c".into(), kind: DepNodeKind::File };

        let a_idx = graph.graph.add_node(a);
        let b_idx = graph.graph.add_node(b);
        let c_idx = graph.graph.add_node(c);

        graph.graph.add_edge(a_idx, b_idx, DepEdge { edge_type: "import".into(), count: 1 });
        graph.graph.add_edge(b_idx, c_idx, DepEdge { edge_type: "import".into(), count: 1 });

        graph.node_map = HashMap::from([
            ("a".into(), a_idx),
            ("b".into(), b_idx),
            ("c".into(), c_idx),
        ]);

        graph
    }

    /// 构建一个包含循环的测试依赖图
    ///
    /// 节点关系：
    ///   A → B → C → A
